 var gr = new GlideRecord('x_2048400_churn_1_customer_profile_table');

 gr.addQuery(
 'company_name',
 vaVars.customer_company_name
 );

 gr.query();

 if (gr.next()) {

 vaVars.customer_found = "true";

 vaVars.company =
 gr.company_name.toString();

 vaVars.risk_score =
 gr.churn_risk_score.toString();

 vaVars.risk_category =
 gr.risk_category.toString();

 vaVars.open_tickets =
 gr.open_tickets.toString();

