 gr.nps_score.toString();

 vaVars.ai_explanation =
 gr.ai_risk_explanation.toString();

 return "Customer found";

 }

 else {

 vaVars.customer_found = "false";

 return "Customer not found";
 }

})();"},"secure":false},{"type":"Decision","name":"Customer_Found_Check","branches":[{"type":"Branch","label":"Customer Found","expression":{"type":"Applicability","mode":"query","value":"customer_found=true"},"id":"544c638571b9479f9cdf59ce0bc4206d","name":"Customer Found","expert_mode":false},{"type":"Branch","label":"customer_not_found","expression":{"type":"Applicability","mode":"query","value":"customer_found=false"},"id":"040c797ab828491f82c2f9f6e8ac616c","name":"customer_not_found","expert_mode":false}],"id":"b5b0a6307d33407c856548ba4b462b6f","goal_id":"primary","expert_mode":false},{"type":"InputPrompt","variable_id":"daa4c3f613294774a3aecce23c3490f2","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Set by NLU", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":false},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"56b84cbfb18e4b44928c80a858b28dd7","name":"customer_found","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"(function() { return (function() { return false; })()})()"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:569add8947700310fdadeee3716d43ed:node:b3a3ab5df16d4d1d9080cacdb2517195:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"b3a3ab5df16d4d1d9080cacdb2517195","name":"Risk_Summary","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"Decision","name":"Risk_Level_Check","branches":[{"type":"Branch","label":"Critical","expression":{"type":"Applicability","mode":"query","value