 var customer = new GlideRecord('u_churn_customer');

 customer.addQuery(
 'u_company_name',
 vaVars.customer_company_name
 );

 customer.query();

 if(customer.next()) {

 var task =
 new GlideRecord('u_churn_intervention');

 task.initialize();

 task.u_customer =
 customer.sys_id;

 task.u_intervention_type =
 'Call';

 task.u_outcome =
 'Pending';

 task.u_notes =
 'Created automatically from Virtual Agent';

 task.insert();

 vaVars.task_message =
 'Retention intervention task created successfully.';
 }

 else {

 vaVars.task_message =
 'Customer not found. Task not created.';
 }

 return vaVars.task_message;

})();"},"secure":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:569add8947700310fdadeee3716d43ed:node:9fdc46f2798749838648c0bfdee1957a:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"9fdc46f2798749838648c0bfdee1957a","name":"Task_Creation_Success","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"gs.getMessageLang("va:topic:569add8947700310fdadeee3716d43ed:node:ba8fae17bf3a40a1b88fe30dff5da5af:field:0", vaContext.getRequesterLang())"}],"request_feedback":true,"isCollapsible":true,"id":"ba8fae17bf3a40a1b88fe30dff5da5af","name":"Customer_Not_Found","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false}],"edges":[{"type":"Edge","source_node_id":"017cb9e3b6b2499b863bb1adecebcf9c","target_node_id":"556f753d9d76402ea3bac9f256b20387","id":"12b34a05933d4e72bd0409e4e692ffb9"},{"type":"Edge","source_node_id":"2f670f0c0c9d4462a26e3c68c828d295","target_node_id":"1ad300bc61b847a7a28acdb70cc7b5ce","branch_id":"254a7822cf804d66966bc2e11b3890f1","id":"95c0819d222c412eb19ca832159f226d","name":"254a7822cf804d66966bc2e11b3890f1"},{"type":"Edge","source_node_id":"7a80940c4aaf433b89c4267e80b6adf7","target_node_id":"b2034ed0b33f492ea18b7d9513c869cd","id":"3d59a10ef0914439bf01bc6537099371"},{"type":"Edge","source_node_id":"b2034ed0b33f492ea18b7d9513c869cd","target_node_id":"bd0a1939eca6466bb01262550eed91cf","id":"a27a5352d9e14d25b18c107336119749"},{"type":"Edge","source_node_id":"bd0a1939eca6466bb01262550eed91cf","target_node_id":"b5b0a6307d33407c856548ba4b462b6f","id":"4303c96c7e7a4845b41119a796208b6a"},{"type":"Edge","source_node_id":"b5b0a6307d33407c856548ba4b462b6f","target_node_id":"b3a3ab5df16d4d1d9080cacdb2517195","branch_id":"544c638571b9479f9cdf