        "1ad300bc61b847a7a28acdb70cc7b5ce": {
          "id": "1ad300bc61b847a7a28acdb70cc7b5ce",
          "stepType": "ScriptOutput",
          "name": "Create_Retention_Task",
          "output_type": "single_part",
          "script": "(function execute() {\n\n    var customer = new GlideRecord('u_churn_customer');\n\n    customer.addQuery(\n        'u_company_name',\n        vaVars.customer_company_name\n    );\n\n    customer.query();\n\n    if(customer.next()) {\n\n        var task =\n        new GlideRecord('u_churn_intervention');\n\n        task.initialize();\n\n        task.u_customer =\n        customer.sys_id;\n\n        task.u_intervention_type =\n        'Call';\n\n        task.u_outcome =\n        'Pending';\n\n        task.u_notes =\n        'Created automatically from Virtual Agent';\n\n        task.insert();\n\n        vaVars.task_message =\n        'Retention intervention task created successfully.';\n    }\n\n    else {\n\n        vaVars.task_message =\n        'Customer not found. Task not created.';\n    }\n\n    return vaVars.task_message;\n\n})();",
          "applicability": {
            "value": "",
            "mode": "query"
          }
        },
